select.isEqual:
SELECT TBAPRDOCINFO.DOCID, TBAPRDOCINFO.HREF, TBAPRRECEIPTPROCESSINFO.SENTDEPTNAME, TBAPRRECEIPTPROCESSINFO.SENTDEPTNAME$v_LANGTYPE$, TBAPRDOCINFO.DOCTITLE, TBAPRRECEIPTPROCESSINFO.DOCSTATE, TBAPRRECEIPTPROCESSINFO.APRSTATE, TBAPRDOCINFO.HASOPINIONYN, TBAPRDOCINFO.DOCTYPE FROM EZAPPROVALG_${companyID}.TBAPRRECEIPTPROCESSINFO INNER JOIN EZAPPROVALG_${companyID}.TBAPRDOCINFO ON TBAPRRECEIPTPROCESSINFO.DOCID = TBAPRDOCINFO.DOCID AND TBAPRRECEIPTPROCESSINFO.TENANT_ID = TBAPRDOCINFO.TENANT_ID INNER JOIN EZAPPROVALG_${companyID}.TBEXPAPRDOCINFO ON TBEXPAPRDOCINFO.DOCID = TBAPRDOCINFO.DOCID AND TBEXPAPRDOCINFO.TENANT_ID = TBAPRDOCINFO.TENANT_ID WHERE TBAPRRECEIPTPROCESSINFO.PROCESSYN <> 'Y' AND TBAPRRECEIPTPROCESSINFO.TENANT_ID = #v_TENANTID# AND ROWNUM <= #v_LISTCOUNT# AND (((TBAPRRECEIPTPROCESSINFO.PROCESSORID = #v_USERID# AND TBAPRRECEIPTPROCESSINFO.RECEIVEDDEPTID = #v_DEPTID#) AND (TBAPRRECEIPTPROCESSINFO.APRSTATE = '012' OR TBAPRRECEIPTPROCESSINFO.APRSTATE = '015'))
OR (TBAPRRECEIPTPROCESSINFO.RECEIVEDDEPTID IN ($v_DEPTIDS$) AND TBAPRRECEIPTPROCESSINFO.APRSTATE IN ('011', '014')) OR (TBAPRRECEIPTPROCESSINFO.RECEIVEDDEPTID IN ($ v_DEPTIDS$) AND TBAPRRECEIPTPROCESSINFO.APRSTATE = '015')
) ORDER BY PROCESSDATE $v_BASICORDER$

